const LoadIngredientsDB = async function(_f) {
  try {
    const response = await fetch(`${_f}?t=${Date.now()}`);
    const data = await response.json();
    return data;
  } catch (err) {
    console.error("❌ Lỗi nạp dữ liệu nguyên liệu:", err);
    return [];
  }
};

function updateShaderUniform() {
  if(!window.DialogueAPI._currentCanvas) return;

  const glWrapper = window.DialogueAPI._currentCanvas;
  const fragSrc = window._codeditor.getValue();

  try {
    // 1. DỌN RÁC (MEMORY MANAGEMENT)
    // Nếu Wrapper của bạn có hàm hủy thì gọi nó (VD: glWrapper.gShader.destroy())
    // Nếu không, hãy gọi thẳng API của WebGL để xóa Program cũ:
    if (glWrapper.gShader && glWrapper.gShader.program) {
      glWrapper.deleteProgram(glWrapper.gShader.program); 
      console.log("thuyshader");
    }

    // 2. BIÊN DỊCH SHADER MỚI
    glWrapper.gShader = new myOpenGL.ThuyShader(glWrapper, glWrapper.gCamera.projectionMatrix, fragSrc).activate();
    console.log("✅ Cập nhật Shader thành công!");

  } catch (err) {
    // Bắt lỗi nếu người dùng gõ code GLSL sai (rất hay xảy ra khi live-coding)
    console.error("❌ Lỗi biên dịch Shader:", err);
  }
}

  // Derivative
