window._loadCalculusLesson = (btnId)=>{
  const lessonName = btnId.split('_').pop(); 
  // 2. Tìm chuỗi lệnh tương ứng trong bộ từ điển
  const _cmds = GEOGEBRA_LESSONS[lessonName];
  // 3. Kiểm tra xem bài học có tồn tại không rồi mới vẽ
  if (_cmds) {
    console.log("Đang tải bài học:", lessonName);
    window.js_local_drawGeoGebra(_cmds);
  } else {
    console.error("Không tìm thấy lệnh GeoGebra cho bài học:", lessonName);
  }
}

