export default async function(Module, entityId, C, API) {
  const e = window.App.entities[window.App.C.GetEntityName(entityId)];
  const speakerName = e.name;

  if (!e.mathQuestion || !e.mathQuestion.endsWith('.md')) {
    console.error("Entity này không có file Markdown câu hỏi!");
    return false;
  }

  // 1. Đọc toàn bộ file MD (Dữ liệu bài giảng)
  const mdContent = await window.readMarkdownFile(e.mathQuestion);

  // ==========================================
  // VÒNG LẶP TRẠNG THÁI (STATE MACHINE)
  // ==========================================
  let currentState = "TEACHING"; // Bắt đầu bằng việc học
  let isInteracting = true;

  while (isInteracting) {

    // ------------------------------------------------
    // TRẠNG THÁI 1: LỚP HỌC (Đọc Markdown)
    // ------------------------------------------------
    if (currentState === "TEACHING") {
      const choices = [
        "✏️ Làm bài tập",
        "❌ Thoát"
      ]

      const selectedIdx = await API.Ask(entityId, speakerName, mdContent, choices, postFunc);

      // Đánh dấu là đã khởi tạo, các vòng lặp sau sẽ truyền null
      // isGlInitialized = true;

      if (selectedIdx === 0) {
        // Chuyển sang state làm bài
        currentState = "PRACTICE"; 
      } else {
        // Bấm Thoát (hoặc tắt hộp thoại trả về -1)
        isInteracting = false; 
      }
    } 

    // ------------------------------------------------
    // TRẠNG THÁI 2: THỰC HÀNH (Trắc nghiệm/Minigame)
    // ------------------------------------------------
    else if (currentState === "PRACTICE") {

      let currentScore = e.npcProgress ? e.npcProgress.solved : 0;

      // Chuẩn bị câu hỏi (Bạn có thể nhúng text câu hỏi riêng vào đây)
      const questionText = `### 🧠 Phần Thực Hành
Bạn hãy áp dụng kiến thức vừa học để giải bài này nhé!

<style>
  table {
    width: 100%;
  }
</style>

| preview | code |
|---|---|
|<canvas id="cv_001" style="width:512px;height:512px;"><canvas> | <div><div id="monaco-safe-zone"></div><button id="btn_001"  onclick="_updateShaderUniform(this.id)">run</button></div>|
`;

      // Tạo mảng lựa chọn (Mình chèn thêm nút Quay lại ở cuối)
      const choices = [
        "Nop bai tap", 
        "🔙 Quay lại bài học" // Lựa chọn cuối cùng
      ];

      const selectedIdx = await API.Ask(entityId, speakerName, questionText, choices, postFunc);

      // Xử lý các lựa chọn
      if (selectedIdx === -1) {
        // Tắt đột ngột UI
        isInteracting = false; 
      } 
      else if (selectedIdx === choices.length - 1) {
        // Nếu chọn nút cuối cùng (Quay lại bài học)
        currentState = "TEACHING"; 
      } 
      else {
        // --- XỬ LÝ LOGIC ĐÚNG/SAI TẠI ĐÂY ---
        // Ví dụ: Giả sử nút đầu tiên (0) là đúng
        if (selectedIdx === 0) {
          window.TriggerFeedback(true);
          // myMathNote.handler_savecmd();
          await API.Say(entityId, speakerName, "### ✅ Bạn da nop bai nhung hay cho cham diem nhe :)");
          currentState = "TEACHING"; 
        } else {
          window.TriggerFeedback(false);
          await API.Say(entityId, speakerName, "### ❌ Sai rồi!\n\nBạn hãy đọc kỹ lại lý thuyết nhé.");
        }
      }
    }
  }

  // ==========================================
  // DỌN DẸP KHI KẾT THÚC HỘI THOẠI
  // ==========================================
  // Dừng vòng lặp WebGL để tiết kiệm pin/CPU
  if (window.DialogueAPI && window.DialogueAPI._currentCanvas) {
    window.DialogueAPI._currentCanvas.glStop();
    // Khuyên dùng: Xóa luôn cờ này để lần mở hội thoại sau nó tạo mới an toàn
    window.DialogueAPI._currentCanvas = null; 
  }

  return true; 
}
